policies.inbound:














        Bearer error="invalid_token"














<set-variable name="userToken" value="@{
    string tokenResponseJson = context.Variables.GetValueOrDefault("userEntraTokenResponse");
    JObject tokenResponse = JObject.Parse(tokenResponseJson);
    return tokenResponse["access_token"]?.ToString();
}" />



    https://login.microsoftonline.com/{{EntraIDTenantId}}/oauth2/v2.0/token
    POST

        application/x-www-form-urlencoded

    @{
        return "grant_type=urn:ietf:params:oauth:grant-type:jwt-bearer" +
               "&client_id={{EntraIDClientId}}" +
               "&client_assertion_type=urn:ietf:params:oauth:client-assertion-type:jwt-bearer" +
               "&client_assertion=" + context.Variables.GetValueOrDefault("ficToken") +
               "&assertion=" + context.Variables.GetValueOrDefault("userToken") +
               "&scope=" + context.Variables.GetValueOrDefault("identifier") + "/user_impersonation" +
               "&requested_token_use=on_behalf_of";
    }



<set-variable name="oboTokenResponse" value="@{
    var response = (IResponse)context.Variables["oboTokenResponse"];
    if (response.StatusCode == 200) {
        return response.Body.As();
    }
    return null;
}" />



    <when condition="@(context.Variables.GetValueOrDefault("oboTokenResponse") == null)">



                application/json

            @{
                var errorResponse = new JObject();
                errorResponse["error"] = "token_exchange_failed";
                errorResponse["error_description"] = "Unable to obtain token for Function App access";
                return errorResponse.ToString();
            }





<cache-store-value key="@($"OBOToken-{context.Variables.GetValueOrDefault("decryptedSessionKey")}")" value="@(context.Variables.GetValueOrDefault("oboTokenResponse"))" duration="3600" />


<set-variable name="oboToken" value="@{
    string responseJson = context.Variables.GetValueOrDefault("oboTokenResponse");
    JObject response = JObject.Parse(responseJson);
    return response["access_token"]?.ToString();
}" />



<set-variable name="oboToken" value="@{
    string cachedResponseJson = context.Variables.GetValueOrDefault("cachedOboToken");
    JObject cachedResponse = JObject.Parse(cachedResponseJson);
    return cachedResponse["access_token"]?.ToString();
}" />

outbound.set-body:
@{
            var accessToken = context.Variables.GetValueOrDefault("oboToken");
            var identifier = context.Variables.GetValueOrDefault("identifier");
            var payloadObject = new
            {
                access_token = accessToken,
                token_type = "Bearer",
                expires_in = 3600,
                refresh_token = "",
                scope = identifier + "/user_impersonation"
            };

            // Serialize the object to a JSON string.
            return Newtonsoft.Json.JsonConvert.SerializeObject(payloadObject);
        }
